/* Helper accessors */
export const projectsByCategory = (cat: ProjectCategory): Project[] =>
  PROJECTS.filter((p) => p.category === cat);

export const projectBySlug = (cat: ProjectCategory, slug: string): Project | undefined =>
  PROJECTS.find((p) => p.category === cat && p.slug === slug);

export const slovenianDate = (date: string): string => {
  const [y, m, d] = date.split("-");
  return `${parseInt(d, 10)}. ${parseInt(m, 10)}. ${y}`;
};
